import{_ as e,o,c as a,ai as t}from"./chunks/framework.CaiDwmc7.js";const g=JSON.parse('{"title":"企业业务套件（CRM / ERP / WMS / IoT）+ 小程序：学习研究总结","description":"","frontmatter":{},"headers":[],"relativePath":"open-source/enterprise-suite.md","filePath":"open-source/enterprise-suite.md"}'),i={name:"open-source/enterprise-suite.md"};function l(n,r,s,c,d,h){return o(),a("div",null,[...r[0]||(r[0]=[t('<h1 id="企业业务套件-crm-erp-wms-iot-小程序-学习研究总结" tabindex="-1">企业业务套件（CRM / ERP / WMS / IoT）+ 小程序：学习研究总结 <a class="header-anchor" href="#企业业务套件-crm-erp-wms-iot-小程序-学习研究总结" aria-label="Permalink to “企业业务套件（CRM / ERP / WMS / IoT）+ 小程序：学习研究总结”">​</a></h1><blockquote><p>目标：<strong>不要做一堆独立项目</strong>，而是用一个“统一后台”把 CRM / ERP / WMS / IoT 串起来，再配套小程序前端。</p></blockquote><hr><h2 id="_1-基础平台-统一后台" tabindex="-1">① 基础平台（统一后台） <a class="header-anchor" href="#_1-基础平台-统一后台" aria-label="Permalink to “① 基础平台（统一后台）”">​</a></h2><ul><li><strong>RuoYi（首选，必须用）</strong></li><li><strong>JeecgBoot（备选）</strong></li></ul><p>建议：以 <strong>RuoYi 二开</strong> 作为企业级“统一后台”骨架（权限、菜单、用户、日志、基础能力先拿到）。</p><hr><h2 id="_2-crm" tabindex="-1">② CRM <a class="header-anchor" href="#_2-crm" aria-label="Permalink to “② CRM”">​</a></h2><ul><li><strong>crm-ebs（轻量好改）</strong></li><li><strong>悟空CRM（国内用得多）</strong></li></ul><p>建议：<strong>基于 RuoYi 扩展 CRM 模块</strong>（更符合招聘与落地方式）。</p><hr><h2 id="_3-erp-进销存-wms-仓库" tabindex="-1">③ ERP（进销存）+ WMS（仓库） <a class="header-anchor" href="#_3-erp-进销存-wms-仓库" aria-label="Permalink to “③ ERP（进销存）+ WMS（仓库）”">​</a></h2><ul><li><strong>ERP</strong><ul><li><strong>JSH ERP（强烈推荐）</strong></li><li>Odoo（偏复杂，不优先）</li></ul></li><li><strong>WMS</strong><ul><li><strong>快仓WMS（轻量）</strong></li><li>OpenWMS（偏复杂）</li></ul></li></ul><p>建议：优先考虑 <strong>在 ERP 里拆 WMS 模块</strong>（更真实、更利于串业务链路）。</p><hr><h2 id="_4-iot-mqtt-设备上线-数据上报" tabindex="-1">④ IoT / MQTT（设备上线 + 数据上报） <a class="header-anchor" href="#_4-iot-mqtt-设备上线-数据上报" aria-label="Permalink to “④ IoT / MQTT（设备上线 + 数据上报）”">​</a></h2><ul><li><strong>EMQX（主流）</strong></li><li><strong>ThingsBoard（完整平台）</strong></li></ul><p>建议：只做 <strong>设备上线、数据上报、简单展示</strong>；尽量别在学习期做过重的复杂平台治理。</p><hr><h2 id="_5-小程序-对接统一后台接口" tabindex="-1">⑤ 小程序（对接统一后台接口） <a class="header-anchor" href="#_5-小程序-对接统一后台接口" aria-label="Permalink to “⑤ 小程序（对接统一后台接口）”">​</a></h2><ul><li><strong>uni-app（首选）</strong></li><li>Taro（备选）</li></ul><p>建议：小程序优先围绕“后台能力”和“业务流程”做接口对接与页面闭环。</p><hr><h2 id="一句话体系建议-可照抄" tabindex="-1">一句话体系建议（可照抄） <a class="header-anchor" href="#一句话体系建议-可照抄" aria-label="Permalink to “一句话体系建议（可照抄）”">​</a></h2><p>用 <code>RuoYi（二开）</code> 做一个“统一后台”，然后在里面加入 <code>CRM / ERP / WMS</code> 模块；再用 <code>EMQX/ThingsBoard</code> 完成 <code>IoT</code> 数据接入；最后用 <code>uni-app</code> 做小程序前端。</p>',25)])])}const u=e(i,[["render",l]]);export{g as __pageData,u as default};
